def word_count(text: str) -> int:
    """Return the number of words in text."""
    return len(text.split())

def unique_word_count(text: str) -> int:
    """Return the number of unique words (case-insensitive)."""
    words = text.lower().split()
    return len(set(words))

def most_common_word(text: str) -> str:
    """Return the most frequent word (case-insensitive)."""
    words = text.lower().split()
    # Count each word
    counts = {}
    for word in words:
        counts[word] = counts.get(word, 0) + 1
    # Find the word with the highest count
    return max(counts, key=lambda w: counts[w])

sample = "the quick brown fox jumps over the lazy dog the fox"

print(f"Words:        {word_count(sample)}")
print(f"Unique words: {unique_word_count(sample)}")
print(f"Most common:  '{most_common_word(sample)}'")

def make_range_validator(min_val: float, max_val: float):
    """Return a validator function that checks if value is in [min_val, max_val]."""
    def validate(value):
        if min_val <= value <= max_val:
            return f"{value} is valid (range {min_val}-{max_val})"
        else:
            return f"{value} is INVALID (must be {min_val}-{max_val})"
    return validate

def make_length_validator(min_len: int, max_len: int):
    """Return a validator function that checks string length."""
    def validate(text):
        length = len(text)
        if min_len <= length <= max_len:
            return f"'{text}' is valid (length {length})"
        else:
            return f"'{text}' is INVALID (length {length}, must be {min_len}-{max_len})"
    return validate

# Create specific validators
age_validator = make_range_validator(0, 120)
grade_validator = make_range_validator(0, 100)
username_validator = make_length_validator(3, 20)

print(age_validator(25))
print(age_validator(150))
print(grade_validator(87))
print(username_validator("alice"))
print(username_validator("ab"))
